SELECT s.submission_no, p.pid, s.language, s.status, s.verdict, s.submit_time, s.finish_time, u.id AS user_id, u.username, u.nickname FROM submission s LEFT JOIN problem p ON s.problem_id = p.id AND p.is_del = 0 LEFT JOIN user_info u ON s.user_id = u.id AND u.is_del = 0 WHERE s.is_del = 0
AND s.user_id = #{userId}
AND s.verdict = #{verdict}
AND s.assignment_id = #{assignmentId}
AND p.pid = #{pid}
AND s.language = #{language}
AND u.username LIKE CONCAT('%', #{username}, '%')
ORDER BY s.submit_time DESC, s.id DESC

SELECT s.submission_no, p.pid, s.language, s.status, s.verdict, s.submit_time, s.finish_time, u.id AS user_id, u.username, u.nickname FROM submission s LEFT JOIN problem p ON s.problem_id = p.id AND p.is_del = 0 LEFT JOIN user_info u ON s.user_id = u.id AND u.is_del = 0 WHERE s.is_del = 0 AND s.problem_id IN
#{pid}
AND s.user_id IN (SELECT user_id FROM class_student_rel WHERE class_id = #{classId} AND is_del = 0) ORDER BY s.submit_time DESC, s.id DESC
